4.9 Main Process


Code
# Step 1 assign

crp_grp_df &lt;- fn_assign_grp(crp_determinants_df)
crp_typ_df &lt;- fn_assign_typ(crp_grp_df)

dcp_grp_df &lt;- fn_assign_grp(dcp_determinants_df)
dcp_typ_df &lt;- fn_assign_typ(dcp_grp_df)

# Step 2 select

crp_grp_df &lt;- crp_grp_df |&gt; select(lat,lon,area,lsm,grp)
crp_typ_df &lt;- crp_typ_df |&gt; select(lat,lon,area,lsm,typ)

dcp_grp_df &lt;- dcp_grp_df |&gt; select(lat,lon,area,lsm,grp)
dcp_typ_df &lt;- dcp_typ_df |&gt; select(lat,lon,area,lsm,typ)

# Step 3 join

ktc_grp_df &lt;- crp_grp_df %&gt;% 
  left_join(dcp_grp_df , by = c("lon", "lat", "lsm")) |&gt;
  rename(cgrp = grp.x, rgrp = grp.y, area = area.x) |&gt;
  select(lon, lat, lsm, area, cgrp, rgrp) |&gt;
  mutate(cgrp = factor(cgrp, levels = ktc_grp_palette_df$grp)) |&gt;
  mutate(rgrp = factor(rgrp, levels = ktc_grp_palette_df$grp))

ktc_typ_df &lt;- crp_typ_df %&gt;% 
  left_join(dcp_typ_df , by = c("lon", "lat", "lsm")) |&gt;
  rename(ctyp = typ.x, rtyp = typ.y, area = area.x) |&gt;
  select(lon, lat, lsm, area, ctyp, rtyp) |&gt;
  mutate(ctyp = factor(ctyp, levels = ktc_typ_palette_df$typ)) |&gt;
  mutate(rtyp = factor(rtyp, levels = ktc_typ_palette_df$typ))

# Step 4 convert to sf

ktc_grp_sf &lt;- st_as_sf(ktc_grp_df, coords = c("lon", "lat"), crs = 4326)
ktc_typ_sf &lt;- st_as_sf(ktc_typ_df, coords = c("lon", "lat"), crs = 4326)

# Step 5 summarize

ktc_grp_cmb_sf &lt;- ktc_grp_sf |&gt;
  filter(lsm &gt; 0) |&gt;
  summarise(
    geometry = st_combine(geometry),
    mkm = sum(area*lsm),
    .by = c(cgrp, rgrp)
  ) |&gt;
  mutate(pct = round(mkm / sum(mkm) * 100, 3)) |&gt;
  select(cgrp, rgrp, mkm, pct, geometry) |&gt;
  arrange(cgrp, rgrp) |&gt;
  st_set_crs(4326)

ktc_typ_cmb_sf &lt;- ktc_typ_sf |&gt;
  filter(lsm &gt; 0) |&gt;
  summarise(
    geometry = st_combine(geometry),
    mkm = sum(area*lsm),
    .by = c(ctyp, rtyp)
  ) |&gt;
  mutate(pct = round(mkm / sum(mkm) * 100, 3)) |&gt;
  select(ctyp, rtyp, mkm, pct, geometry) |&gt;
  arrange(ctyp, rtyp) |&gt;
  st_set_crs(4326)

# Step 6 crp summary df

crp_grp_tbl_df &lt;- ktc_grp_cmb_sf |&gt;
  st_drop_geometry() |&gt;
  rename(grp = cgrp) |&gt;
  select(grp, mkm, pct) |&gt;
  summarise(
    mkm = sum(mkm),
    pct = sum(pct),
    .by = grp
  )|&gt;
  arrange(grp)

crp_typ_tbl_df &lt;- ktc_typ_cmb_sf |&gt;
  st_drop_geometry() |&gt;
  rename(typ = ctyp) |&gt;
  select(typ, mkm, pct) |&gt;
  summarise(
    mkm = sum(mkm),
    pct = sum(pct),
    .by = typ
  )|&gt;
  arrange(typ)

# Step 7 dcp summary df

dcp_grp_tbl_df &lt;- ktc_grp_cmb_sf |&gt;
  st_drop_geometry() |&gt;
  rename(grp = rgrp) |&gt;
  select(grp, mkm, pct) |&gt;
  summarise(
    mkm = sum(mkm),
    pct = sum(pct),
    .by = grp
  )|&gt;
  arrange(grp)

dcp_typ_tbl_df &lt;- ktc_typ_cmb_sf |&gt;
  st_drop_geometry() |&gt;
  rename(typ = rtyp) |&gt;
  select(typ, mkm, pct) |&gt;
  summarise(
    mkm = sum(mkm),
    pct = sum(pct),
    .by = typ
  )|&gt;
  arrange(typ)

5.8 Functions


Code
fn_build_summary_table &lt;- function(df) {
  tbl &lt;- df |&gt;
    gt(rowname_col = "cg" ) |&gt;
    tab_stubhead(label = "Group")|&gt;
    tab_header(
      title = "Köppen-Trewartha Climate Classification",
      subtitle = "Group Changes Summary",
    ) |&gt;
    tab_spanner(
      label = "Area (Mkm²)",
      columns = c(mkm_c, mkm_g, mkm_l, mkm_r, mkm_d)
    ) |&gt;
    tab_spanner(
      label = "Group % of Total",
      columns = c(pct_c, pct_g, pct_l, pct_r, pct_d)
    ) |&gt;
    cols_label(
      mkm_c = "CRP",
      mkm_g = "Gain",
      mkm_l = "Loss",
      mkm_r = "DCP",
      mkm_d = "Net Chg",

      pct_c = "CRP",
      pct_g = "Gain",
      pct_l = "Loss",
      pct_r = "DCP",
      pct_d = "Net Chg"
    ) |&gt;
    fmt_number(
      columns = c(mkm_c, mkm_g, mkm_l, mkm_r, mkm_d),
      decimals = 1) |&gt;
    fmt_percent(
      columns = c(pct_c, pct_g, pct_l, pct_r, pct_d),
      decimals = 1 
    ) |&gt;
    grand_summary_rows(
      columns = c(mkm_c, mkm_g, mkm_l, mkm_r, mkm_d),
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_number(.x, decimals = 1)) 
    ) |&gt;
    grand_summary_rows(
      columns = c(pct_c, pct_g, pct_l, pct_r, pct_d),
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_percent(.x, decimals = 1)) 
    ) |&gt;
    tab_footnote(
      footnote = paste("Climatological Reference Period ", crp_beg, "-", crp_end, sep = ""),
      locations = cells_column_labels(columns = c(mkm_c, pct_c))
    ) |&gt;
    tab_footnote(
      footnote = paste("Recent Climate Period ", dcp_beg, "-", dcp_end, sep = ""),
      locations = cells_column_labels(columns = c(mkm_r, pct_r))
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#e6f0fa"),
      locations = cells_body(columns = pct_g, rows = pct_g &gt; .01)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#c5d6e9"),
      locations = cells_body(columns = pct_g, rows = pct_g &gt; .02)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#fffad5"),
      locations = cells_body(columns = pct_l, rows = pct_l &lt; -.01)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#fff7bc"),
      locations = cells_body(columns = pct_l, rows = pct_l &lt; -.02)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#c5d6e9"),
      locations = cells_body(columns = pct_d, rows = pct_d &gt; .02)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#fff7bc"),
      locations = cells_body(columns = pct_d, rows = pct_d &lt; -.01)
    )

  return(tbl)
}




Code
fn_build_detail_table &lt;- function(df, subtitle) {

  tbl &lt;- df |&gt;
    gt(rowname_col = "cgrp" ) |&gt;
    tab_stubhead(label = "From Group")|&gt;
    tab_header(
      title = "Climate Classification Changes Detail",
      subtitle = subtitle
    ) |&gt;
    cols_label(
      rgrp = "To Group",
      mkm = "Area (Mkm²)",
      pct = "Land Area %",
    ) |&gt;
    fmt_number(
      columns = mkm,
      decimals = 1
    ) |&gt;
    fmt_percent(
      columns = pct,
      decimals = 2 
    ) |&gt;
    # cols_width(
    #     col_a ~ px(150), # Set col_a to 150 pixels
    #     col_b ~ pct(10), # Set col_b to 10% of table width
    #     everything() ~ px(200) # Set all other columns to 200 pixels
    # ) |&gt;
    grand_summary_rows(
      columns = mkm,
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_number(.x, decimals = 1))
    ) |&gt;
    grand_summary_rows(
      columns = pct,
      fns = list("Total" = ~ sum(.)),
      fmt = list(~ fmt_percent(.x, decimals = 2)) 
    ) |&gt;

    tab_style(
      style = cell_fill(color = "#e6f0fa"),
      locations = cells_body(columns = pct, rows = pct &gt; .01)
    ) |&gt;
    tab_style(
      style = cell_fill(color = "#c5d6e9"),
      locations = cells_body(columns = pct, rows = pct &gt; .02)
    )

  return(tbl)
}




Code
fn_build_global_map &lt;- function(plot_data, palette, cp) {

  p &lt;- ggplot(plot_data) +
    geom_sf(aes(color = grp), size = 0.01) +
    scale_color_manual(values = palette, drop = FALSE) +
    geom_sf(data = coastline_sf, color = "black", linewidth = 0.1) +
    coord_sf(crs = rbn_prj) +
    guides(color = guide_legend(override.aes = list(size = 4 ))) # legend point size

  if (cp == "dcp") {
    p &lt;- p +  
      labs(
        title = "Climate Group Classification Changes ",
        color = "New\nGroup"
      )
  } else {
    p &lt;- p + labs(color = "Old\nGroup")
  }

  return(p)
}
